#!/usr/bin/env python3

import json
import logging
from flask import Flask, jsonify
from bitcoinlib.services.services import Service
from bitcoinlib.networks import Network
import requests
import socket

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

app = Flask(__name__)

# Bitcoin network configuration
BITCOIN_P2P_PORT = 8333
BITCOIN_RPC_PORT = 8332
BITCOIN_RPC_USER = 'bitcoin'
BITCOIN_RPC_PASSWORD = 'password'

class BitcoinService:
    def __init__(self):
        self.service = None
        self.network_status = 'offline'
        self.initialize_service()

    def initialize_service(self):
        """Initialize connection to Bitcoin network"""
        try:
            # Try to connect to Bitcoin network using bitcoinlib
            self.service = Service(network='bitcoin', providers=['bitcoinlib'], timeout=10)

            # Test connection by getting latest block
            latest_block = self.service.getblock(None, 0, 1)
            if latest_block:
                self.network_status = 'online'
                logger.info("Successfully connected to Bitcoin network")
            else:
                self.network_status = 'offline'
                logger.warning("Connected to Bitcoin network but no blocks available")

        except Exception as e:
            self.network_status = 'offline'
            logger.error(f"Failed to connect to Bitcoin network: {e}")

    def get_block_by_hash(self, block_hash):
        """Get block details by hash"""
        try:
            if not self.service:
                return None

            # Get block data
            block_data = self.service.getblock(block_hash)
            if not block_data:
                return None

            # Extract required fields according to schema
            block_info = {
                'hash': block_hash,
                'height': block_data.get('height', 0),
                'merkleroot': block_data.get('merkleroot', ''),
                'time': block_data.get('time', 0),
                'nonce': block_data.get('nonce', 0),
                'tx': block_data.get('tx', [])
            }

            return block_info

        except Exception as e:
            logger.error(f"Error getting block {block_hash}: {e}")
            return None

    def get_transaction_by_id(self, txid):
        """Get transaction details by ID"""
        try:
            if not self.service:
                return None

            # Get transaction data
            tx_data = self.service.gettransaction(txid)
            if not tx_data:
                return None

            # Extract required fields according to schema
            transaction_info = {
                'txid': txid,
                'blockhash': tx_data.get('blockhash', ''),
                'vin': [],
                'vout': []
            }

            # Process transaction inputs (vin)
            for vin in tx_data.get('vin', []):
                input_data = {
                    'coinbase': vin.get('coinbase', ''),
                    'sequence': vin.get('sequence', 0)
                }
                transaction_info['vin'].append(input_data)

            # Process transaction outputs (vout)
            for vout in tx_data.get('vout', []):
                output_data = {
                    'value': vout.get('value', 0.0),
                    'n': vout.get('n', 0),
                    'scriptPubKey': {
                        'asm': vout.get('scriptPubKey', {}).get('asm', ''),
                        'hex': vout.get('scriptPubKey', {}).get('hex', ''),
                        'type': vout.get('scriptPubKey', {}).get('type', '')
                    }
                }
                transaction_info['vout'].append(output_data)

            return transaction_info

        except Exception as e:
            logger.error(f"Error getting transaction {txid}: {e}")
            return None

# Initialize Bitcoin service
bitcoin_service = BitcoinService()

@app.route('/block/<block_hash>', methods=['GET'])
def get_block(block_hash):
    """Get block details by hash"""
    try:
        block_data = bitcoin_service.get_block_by_hash(block_hash)

        if block_data is None:
            return jsonify({'error': 'Block not found'}), 404

        return jsonify(block_data)

    except Exception as e:
        logger.error(f"Error in get_block endpoint: {e}")
        return jsonify({'error': 'Internal server error'}), 500

@app.route('/transaction/<txid>', methods=['GET'])
def get_transaction(txid):
    """Get transaction details by ID"""
    try:
        transaction_data = bitcoin_service.get_transaction_by_id(txid)

        if transaction_data is None:
            return jsonify({'error': 'Transaction not found'}), 404

        return jsonify(transaction_data)

    except Exception as e:
        logger.error(f"Error in get_transaction endpoint: {e}")
        return jsonify({'error': 'Internal server error'}), 500

@app.route('/status', methods=['GET'])
def get_status():
    """Get network status"""
    try:
        status_data = {
            'status': bitcoin_service.network_status
        }
        return jsonify(status_data)

    except Exception as e:
        logger.error(f"Error in get_status endpoint: {e}")
        return jsonify({'error': 'Internal server error'}), 500

@app.errorhandler(404)
def not_found(error):
    """Handle 404 errors"""
    return jsonify({'error': 'Endpoint not found'}), 404

@app.errorhandler(500)
def internal_error(error):
    """Handle 500 errors"""
    return jsonify({'error': 'Internal server error'}), 500

if __name__ == '__main__':
    logger.info("Starting Bitcoin Service API...")
    logger.info(f"Network status: {bitcoin_service.network_status}")

    # Run Flask app on localhost port 5000
    app.run(host='0.0.0.0', port=5000, debug=False)
